/*
  1. Try to parse toolCalls[0].function.arguments (agent path)
  2. If empty, check message.analysis.structuredData  (EoC path)
  3. If still empty, check message.artifact.analysis.structuredData (legacy)
  4. Set hasStructuredData = true when we find appointmentType etc.
*/

const msg   = $json.message || {};
let   data  = {};   // will hold the structured object we find
let   found = false;

// ---------- Helper -----------
const looksValid = (obj = {}) => {
  const required = ['appointmentType', 'appointmentDateTime', 'callerName'];
  return required.every(k => obj?.[k]);
};

// ---------- 1) agent tool call ----------
try {
  const argStr = msg.toolCalls?.[0]?.function?.arguments || '{}';
  const parsed = JSON.parse(argStr);
  if (looksValid(parsed)) {
    data  = parsed;
    found = true;
  }
} catch (e) {
  // ignore parse errors
}

// ---------- 2) new EoC property ----------
if (!found && looksValid(msg.analysis?.structuredData)) {
  data  = msg.analysis.structuredData;
  found = true;
}

// ---------- 3) legacy artifact path ----------
if (!found && looksValid(msg.artifact?.analysis?.structuredData)) {
  data  = msg.artifact.analysis.structuredData;
  found = true;
}

// ---------- Output ----------
return [
  {
    json: {
      ...$json,
      structuredData: data,      // pass the object forward
      hasStructuredData: found   // flag for IF node
    }
  }
];

